29	
30	const componentGroupPremium = (count: number): number =>
31	  count === COMPONENT_BLOCK_SIZE
32	    ? COMPONENT_BLOCK_PREMIUM
33	    : count * COMPONENT_BASE_PREMIUM;
34	
35	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
36	
37	const isHighEnchantment = (item: Item): boolean =>
38	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
39	
40	const qualifiesForFirstInsurance = (item: Item, isSingleItemPolicy: boolean): boolean =>
41	  isSingleItemPolicy && !!item.cursed && !isHighEnchantment(item);
42	
43	const surchargeRates = (item: Item, isSingleItemPolicy: boolean): number[] => [
44	  item.cursed ? CURSE_SURCHARGE_RATE : 0,
45	  isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0,
46	  qualifiesForFirstInsurance(item, isSingleItemPolicy) ? FIRST_INSURANCE_RATE : 0,
47	];
48	
49	const mainItemPremium = (item: Item, isSingleItemPolicy: boolean): number => {
50	  const base = BASE_PREMIUM_BY_TYPE[item.type];
51	  const totalRate = surchargeRates(item, isSingleItemPolicy).reduce((a, b) => a + b, 1);
52	  return base * totalRate;
53	};
54	
55	const countByType = (items: Item[]): Map<string, number> =>
56	  items.reduce(
57	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
58	    new Map<string, number>(),
59	  );
60	
61	const sumComponentPremiums = (components: Item[]): number =>
62	  [...countByType(components).values()]
63	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
64	
65	const partitionItems = (items: Item[]): { mains: Item[]; components: Item[] } =>
66	  items.reduce<{ mains: Item[]; components: Item[] }>(
67	    (acc, item) => {
68	      (isMainItem(item) ? acc.mains : acc.components).push(item);
69	      return acc;
70	    },
71	    { mains: [], components: [] },
72	  );
73	
74	const sumItemPremiums = (items: Item[], policyRate: number): number => {
75	  const { mains, components } = partitionItems(items);
76	  const isSingleItemPolicy = items.length === 1;
77	  const mainsBaseSum = mains.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
78	  const mainsPremiumSum = mains.reduce((sum, item) => sum + mainItemPremium(item, isSingleItemPolicy), 0);
79	  const componentsSum = sumComponentPremiums(components);
80	  return mainsPremiumSum + componentsSum + (mainsBaseSum + componentsSum) * policyRate;
81	};
82	
83	const customerRateAdjustments = (customer: Customer, isFollowUp: boolean): number[] => [
84	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -LOYALTY_DISCOUNT_RATE : 0,
85	  customer.firstQuote ? FIRST_INSURANCE_RATE : 0,
86	  isFollowUp ? -FOLLOWUP_DISCOUNT_RATE : 0,
87	];
88	
89	const policyWideRate = (customer: Customer, isFollowUp: boolean): number =>
90	  customerRateAdjustments(customer, isFollowUp).reduce((sum, rate) => sum + rate, 0);
91	
92	const ceilInFavor = (value: number): number => Math.ceil(Number(value.toFixed(6)));
93	
94	const quotePremiumFor = (step: Step, customer: Customer, isFollowUp: boolean): { premium: number } => ({
95	  premium: ceilInFavor(sumItemPremiums(step.items, policyWideRate(customer, isFollowUp)) + PROCESSING_FEE),
96	});
97	
98	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
99	  results: scenario.steps.map((step, i) => quotePremiumFor(step, scenario.customer, i > 0)),
100	});
